    "pricing.trustTrial": { es: "Prueba gratuita de 7 días", fr: "Essai gratuit de 7 jours", de: "7 Tage kostenlos", it: "Prova gratuita di 7 giorni", pt: "Teste gratuito de 7 dias", nl: "7 dagen gratis", sv: "7 dagars gratis", no: "7 dagers gratis", da: "7 dages gratis", fi: "7 päivän ilmainen", pl: "7 dni za darmo" },
