    "audit.noCreditCard": { es: "Sin tarjeta de crédito. Tu informe estará listo en menos de 2 minutos.", fr: "Sans carte de crédit. Votre rapport sera prêt en moins de 2 minutes.", de: "Keine Kreditkarte nötig. Ihr Bericht ist in unter 2 Minuten fertig.", it: "Nessuna carta di credito. Il tuo rapporto sarà pronto in meno di 2 minuti.", pt: "Sem cartão de crédito. Seu relatório estará pronto em menos de 2 minutos.", nl: "Geen creditcard nodig. Uw rapport is in minder dan 2 minuten klaar.", sv: "Inget kreditkort krävs. Din rapport är klar på under 2 minuter.", no: "Ingen kredittkort nødvendig. Rapporten din er klar på under 2 minutter.", da: "Intet kreditkort påkrævet. Din rapport er klar på under 2 minutter.", fi: "Ei luottokorttia. Raporttisi on valmis alle 2 minuutissa.", pl: "Bez karty kredytowej. Raport będzie gotowy w mniej niż 2 minuty." },
    "audit.whatInReport": { es: "¿Qué incluye tu informe de auditoría?", fr: "Que contient votre rapport d'audit ?", de: "Was enthält Ihr Audit-Bericht?", it: "Cosa include il tuo rapporto di audit?", pt: "O que está no seu relatório de auditoria?", nl: "Wat zit er in uw auditrapport?", sv: "Vad innehåller din granskningsrapport?", no: "Hva er i revisjonsrapporten din?", da: "Hvad er i din revisionsrapport?", fi: "Mitä tarkastusraportissasi on?", pl: "Co zawiera Twój raport audytu?" },
    "audit.whatInReportDesc": { es: "Nuestro motor de IA realiza un análisis completo de tu presencia online y rendimiento publicitario.", fr: "Notre moteur IA effectue une analyse complète de votre présence en ligne et de vos performances publicitaires.", de: "Unsere KI-Engine führt eine umfassende Analyse Ihrer Online-Präsenz und Anzeigenleistung durch.", it: "Il nostro motore IA esegue un'analisi completa della tua presenza online e delle prestazioni pubblicitarie.", pt: "Nosso motor de IA realiza uma análise abrangente da sua presença online e desempenho publicitário.", nl: "Onze AI-engine voert een uitgebreide analyse uit van uw online aanwezigheid en advertentieprestaties.", sv: "Vår AI-motor utför en omfattande analys av din onlinenärvaro och annonsprestanda.", no: "Vår AI-motor utfører en omfattende analyse av din tilstedeværelse på nett og annonseytelse.", da: "Vores AI-motor udfører en omfattende analyse af din online tilstedeværelse og annonceydelse.", fi: "Tekoälymoottorimme suorittaa kattavan analyysin verkkonäkyvyydestäsi ja mainosten suorituskyvystä.", pl: "Nasz silnik AI przeprowadza kompleksową analizę Twojej obecności online i wydajności reklam." },
    "audit.readyToDiscover": { es: "¿Listo para descubrir oportunidades ocultas?", fr: "Prêt à découvrir des opportunités cachées ?", de: "Bereit, verborgene Chancen zu entdecken?", it: "Pronto a scoprire opportunità nascoste?", pt: "Pronto para descobrir oportunidades ocultas?", nl: "Klaar om verborgen kansen te ontdekken?", sv: "Redo att upptäcka dolda möjligheter?", no: "Klar for å oppdage skjulte muligheter?", da: "Klar til at opdage skjulte muligheder?", fi: "Oletko valmis löytämään piilossa olevia mahdollisuuksia?", pl: "Gotowy odkryć ukryte możliwości?" },
    "audit.joinThousands": { es: "Únete a miles de empresas que han encontrado insights prácticos con nuestra herramienta de auditoría gratuita.", fr: "Rejoignez des milliers d'entreprises qui ont trouvé des insights actionnables grâce à notre outil d'audit gratuit.", de: "Schließen Sie sich Tausenden von Unternehmen an, die mit unserem kostenlosen Audit-Tool verwertbare Erkenntnisse gewonnen haben.", it: "Unisciti a migliaia di aziende che hanno trovato insight pratici con il nostro strumento di audit gratuito.", pt: "Junte-se a milhares de empresas que encontraram insights práticos com nossa ferramenta de auditoria gratuita.", nl: "Sluit u aan bij duizenden bedrijven die bruikbare inzichten hebben gevonden met onze gratis audittool.", sv: "Gå med tusentals företag som har hittat praktiska insikter med vårt gratis granskningsverktyg.", no: "Bli med tusenvis av bedrifter som har funnet praktisk innsikt med vårt gratis revisjonsverktøy.", da: "Slut dig til tusindvis af virksomheder, der har fundet handlingsorienteret indsigt med vores gratis revisionsværktøj.", fi: "Liity tuhansien yritysten joukkoon, jotka ovat löytäneet käytännöllisiä oivalluksia ilmaisella tarkastustyökalullamme.", pl: "Dołącz do tysięcy firm, które znalazły praktyczne wnioski dzięki naszemu bezpłatnemu narzędziu audytu." },
    "audit.startFreeAudit": { es: "Comienza tu auditoría gratuita", fr: "Commencez votre audit gratuit", de: "Starten Sie Ihr kostenloses Audit", it: "Inizia il tuo audit gratuito", pt: "Comece sua auditoria gratuita", nl: "Begin uw gratis audit", sv: "Starta din gratis granskning", no: "Start din gratis revisjon", da: "Start din gratis revision", fi: "Aloita ilmainen tarkastus", pl: "Rozpocznij bezpłatny audyt" },

