    "about.heroTitle1": { es: "Google Ads no debería ser tan difícil.", fr: "Google Ads ne devrait pas être si compliqué.", de: "Google Ads sollte nicht so schwer sein.", it: "Google Ads non dovrebbe essere così difficile.", pt: "Google Ads não deveria ser tão difícil.", nl: "Google Ads zou niet zo moeilijk moeten zijn.", sv: "Google Ads borde inte vara så svårt.", no: "Google Ads burde ikke være så vanskelig.", da: "Google Ads burde ikke være så svært.", fi: "Google Adsin ei pitäisi olla näin vaikeaa.", pl: "Google Ads nie powinno być aż tak trudne." },
    "about.heroTitle2": { es: "Estamos cambiando eso.", fr: "Nous changeons cela.", de: "Das ändern wir.", it: "Stiamo cambiando tutto.", pt: "Estamos mudando isso.", nl: "Wij veranderen dat.", sv: "Vi ändrar på det.", no: "Vi endrer det.", da: "Vi ændrer det.", fi: "Me muutamme sen.", pl: "Zmieniamy to." },
    "about.heroDesc": { es: "AdMaster Pro hace que Google Ads sea simple, asequible y realmente útil para pequeñas empresas.", fr: "AdMaster Pro rend Google Ads simple, abordable et vraiment utile pour les petites entreprises.", de: "AdMaster Pro macht Google Ads einfach, erschwinglich und wirklich nützlich für kleine Unternehmen.", it: "AdMaster Pro rende Google Ads semplice, conveniente e davvero utile per le piccole imprese.", pt: "AdMaster Pro torna o Google Ads simples, acessível e realmente útil para pequenas empresas.", nl: "AdMaster Pro maakt Google Ads eenvoudig, betaalbaar en echt nuttig voor kleine bedrijven.", sv: "AdMaster Pro gör Google Ads enkelt, prisvärt och verkligen användbart för småföretag.", no: "AdMaster Pro gjør Google Ads enkelt, rimelig og virkelig nyttig for små bedrifter.", da: "AdMaster Pro gør Google Ads enkelt, overkommeligt og virkelig nyttigt for små virksomheder.", fi: "AdMaster Pro tekee Google Adsista yksinkertaisen, edullisen ja todella hyödyllisen pienyrityksille.", pl: "AdMaster Pro sprawia, że Google Ads jest proste, przystępne i naprawdę przydatne dla małych firm." },
