// Read each language file, find the closing `} as const;` and insert new keys before it
const langs = ["es", "fr", "de", "it", "pt", "nl", "sv", "no", "da", "fi", "pl"];

for (const lang of langs) {
    const filePath = path.join(messagesDir, `${lang}.ts`);
    let content = fs.readFileSync(filePath, "utf-8");

    // Check if we already added flat keys
    if (content.includes('"common.logIn"')) {
        console.log(`[${lang}] Already has flat keys, skipping.`);
        continue;
    }

    // Build the new keys block
    let newBlock = `\n    // ─── Flat aliases used by page components ───────────────────────────\n`;

    for (const [key, langValues] of Object.entries(translations)) {
        const value = langValues[lang];
        if (value) {
            // Escape single quotes in values
            const escaped = value.replace(/'/g, "\\'");
            newBlock += `    "${key}": "${escaped}",\n`;
        }
    }

    // Insert before the closing `};`
    const closingPattern = /\};\s*\nexport default/m;
    if (closingPattern.test(content)) {
        content = content.replace(closingPattern, `${newBlock}};\n\nexport default`);
        fs.writeFileSync(filePath, content);
        console.log(`[${lang}] Added ${Object.keys(translations).length} flat keys.`);
    } else {
        console.error(`[${lang}] Could not find closing pattern.`);
    }
}

console.log("Done!");
